<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Quick Sort Interactive Visualization-Algorithms Innovation Hub</title><link rel="stylesheet" href="quick.css"><style>#history-log{max-height:150px;overflow-y:auto;background:#f0f0f0;padding:10px;border-radius:5px;color:black}
#history-log{max-height:150px;overflow-y:auto;background:#f0f0f0;padding:10px;border-radius:5px;color:#000}#history-log p{margin:5px 0;font-size:.9em}#speed-control{margin:10px 0}body{margin:0;overflow:hidden;font-family:'Segoe UI',Arial,sans-serif;background:linear-gradient(135deg,#1e3c72,#2a5298);color:#fff}canvas{display:block}#controls{position:absolute;top:20px;left:20px;background:rgb(0 0 0 / .85);padding:15px;border-radius:10px;box-shadow:0 4px 10px rgb(0 0 0 / .5);animation:slideIn 0.5s ease-out}#info{position:absolute;top:220px;left:20px;background:rgb(0 0 0 / .85);padding:15px;max-width:400px;font-size:16px;border-radius:10px;box-shadow:0 4px 10px rgb(0 0 0 / .5);animation:slideIn 0.5s ease-out 0.2s;animation-fill-mode:backwards}#controls input,#controls button{margin:8px 0;padding:8px;font-size:14px;border-radius:5px;border:none;transition:transform 0.2s,background 0.2s}#controls input{width:200px;background:#fff;color:#333}#controls button{cursor:pointer;background:linear-gradient(45deg,#4CAF50,#66BB6A);color:#fff;margin-right:10px;border-radius:3px}#controls button:hover:not(:disabled){transform:scale(1.05);background:linear-gradient(45deg,#66BB6A,#4CAF50)}#controls button:disabled{background:#666;cursor:not-allowed}#array-state,#score,#progress{margin-top:10px;font-size:14px}#progress-bar{width:100%;height:10px;background:#333;border-radius:5px;overflow:hidden}#progress-fill{height:100%;background:linear-gradient(45deg,#2196F3,#64B5F6);transition:width 0.3s ease}#footer{position:absolute;bottom:60px;right:40px;font-size:18px;color:#8e8787;background:rgb(0 0 0 / .7);padding:5px 10px;border-radius:5px;animation:slideIn 0.5s ease-out 0.4s;animation-fill-mode:backwards;z-index:1111111}.tooltip{position:relative;display:inline-block}.tooltip .tooltiptext{visibility:hidden;width:120px;background:#333;color:#fff;text-align:center;border-radius:5px;padding:5px;position:absolute;z-index:1;bottom:125%;left:50%;margin-left:-60px;opacity:0;transition:opacity 0.3s}.tooltip:hover .tooltiptext{visibility:visible;opacity:1}@keyframes slideIn{from{transform:translateY(-20px);opacity:0}to{transform:translateY(0);opacity:1}}@keyframes pulse{0%{transform:scale(1)}50%{transform:scale(1.1)}100%{transform:scale(1)}}
</style></head><body><div id="controls"><div><label for="numbers">Enter numbers(comma-separated):</label><br><input type="text" id="numbers" placeholder="e.g., 5,2,8,1" size="20"></div><div class="tooltip"><button id="start">Start Sorting</button><span class="tooltiptext">Begin sorting your numbers</span></div><div class="tooltip"><button id="random">Randomize</button><span class="tooltiptext">Generate a random array</span></div><div class="tooltip"><button id="prev" disabled>Previous</button><span class="tooltiptext">Go to previous step</span></div><div class="tooltip"><button id="next" disabled>Next</button><span class="tooltiptext">Go to next step</span></div><div class="tooltip"><button id="play">Play</button><span class="tooltiptext">Play or pause animation</span></div><div class="tooltip"><button id="sound-toggle">Sound:On</button><span class="tooltiptext">Toggle sound effects</span></div><div id="speed-control"><label for="speed">Animation Speed:</label><input type="range" id="speed" min="0.5" max="2" step="0.1" value="1"><span id="speed-value">1x</span><div id="array-state">Current Array:[]</div><div id="score" style="display: none;">Score:0</div></div><div id="info">Enter numbers and click Start Sorting to begin the Quick Sort adventure!</div><br><br><br><br><div id="step-counter" style="display: none;">Step:0/0</div><div id="progress">Progress:0%</div><div id="progress-bar"><div id="progress-fill" style="width: 0%"></div></div><div id="history-log"></div></div><div id="footer"><b>Powered by<br>Awarcrown Corporations</b></div><script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r134/three.min.js"></script><script src="https://cdn.jsdelivr.net/npm/js-confetti@0.11.0/dist/js-confetti.browser.js"></script><script>const scene=new THREE.Scene();const camera=new THREE.PerspectiveCamera(75,window.innerWidth/window.innerHeight,0.1,1000);const renderer=new THREE.WebGLRenderer({antialias:!0});renderer.setSize(window.innerWidth,window.innerHeight);document.body.appendChild(renderer.domElement);camera.position.z=20;camera.position.y=5;camera.lookAt(0,0,0);const particleGeometry=new THREE.BufferGeometry();const particleCount=1000;const positions=new Float32Array(particleCount*3);const velocities=new Float32Array(particleCount*3);for(let i=0;i<particleCount*3;i+=3){positions[3*i]=(Math.random()-0.5)*100;positions[3*i+1]=(Math.random()-0.5)*100;positions[3*i+2]=(Math.random()-0.5)*100;velocities[3*i]=(Math.random()-0.5)*0.02;velocities[3*i+1]=(Math.random()-0.5)*0.02;velocities[3*i+2]=(Math.random()-0.5)*0.02}
particleGeometry.setAttribute('position',new THREE.BufferAttribute(positions,3));const particleMaterial=new THREE.PointsMaterial({color:0x64B5F6,size:0.2});const particles=new THREE.Points(particleGeometry,particleMaterial);scene.add(particles);let array=[];let cubes=[];const cubeSize=1;const spacing=1.5;let animationSteps=[];let currentStep=0;let stepTimer=0;let stepDuration=1000;let isPlaying=!1;let score=0;let speed=1;let soundEnabled=!0;let pivotLine=null;const colors={normal:new THREE.Color(0x00ff00),pivot:new THREE.Color(0xff00ff),comparing:new THREE.Color(0xffa500),swapping:new THREE.Color(0xff0000),sorted:new THREE.Color(0x0000ff)};const ctx=new(window.AudioContext||window.webkitAudioContext)();function playSound(frequency,type='sine',duration=0.1){if(!soundEnabled)return;const oscillator=ctx.createOscillator();const gainNode=ctx.createGain();oscillator.type=type;oscillator.frequency.setValueAtTime(frequency,ctx.currentTime);gainNode.gain.setValueAtTime(0.5,ctx.currentTime);oscillator.connect(gainNode);gainNode.connect(ctx.destination);oscillator.start();oscillator.stop(ctx.currentTime+duration)}
function createTextTexture(text){const canvas=document.createElement('canvas');canvas.width=128;canvas.height=128;const ctx=canvas.getContext('2d');ctx.fillStyle='white';ctx.fillRect(0,0,canvas.width,canvas.height);ctx.fillStyle='black';ctx.font='bold 80px Arial';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(text,canvas.width/2,canvas.height/2);return new THREE.CanvasTexture(canvas)}
function createPivotLine(index){if(pivotLine)scene.remove(pivotLine);const material=new THREE.LineBasicMaterial({color:0xff00ff});const points=[];const x=(index-array.length/2)*spacing;points.push(new THREE.Vector3(x,-1,0));points.push(new THREE.Vector3(x,3,0));const geometry=new THREE.BufferGeometry().setFromPoints(points);pivotLine=new THREE.Line(geometry,material);scene.add(pivotLine)}
function createCubes(){cubes.forEach(cube=>scene.remove(cube));if(pivotLine)scene.remove(pivotLine);pivotLine=null;cubes=[];array.forEach((value,index)=>{const geometry=new THREE.BoxGeometry(cubeSize,cubeSize,cubeSize);const materials=[new THREE.MeshBasicMaterial({map:createTextTexture(value)}),new THREE.MeshBasicMaterial({map:createTextTexture(index)}),new THREE.MeshBasicMaterial({color:colors.normal}),new THREE.MeshBasicMaterial({color:colors.normal}),new THREE.MeshBasicMaterial({map:createTextTexture(value)}),new THREE.MeshBasicMaterial({map:createTextTexture(index)})];const cube=new THREE.Mesh(geometry,materials);cube.position.x=(index-array.length/2)*spacing;cube.position.y=0;scene.add(cube);cubes.push(cube)});updateCamera()}
function updateCamera(){const arrayWidth=array.length*spacing;camera.position.z=Math.max(20,arrayWidth/2+10);camera.position.y=arrayWidth/4;camera.lookAt(0,0,0)}
function quickSort(arr,low,high,steps){if(low<high){steps.push({type:'partition_start',low,high,description:`Partitioning array from index ${low} to ${high}.`,arrayState:[...arr]});const pi=partition(arr,low,high,steps);steps.push({type:'partition_end',pivotIndex:pi,description:`Pivot ${arr[pi]} placed at index ${pi}.`,arrayState:[...arr]});steps.push({type:'recurse',low,high:pi-1,description:`Sorting subarray from index ${low} to ${pi - 1}.`,arrayState:[...arr]});quickSort(arr,low,pi-1,steps);steps.push({type:'recurse',low:pi+1,high,description:`Sorting subarray from index ${pi + 1} to ${high}.`,arrayState:[...arr]});quickSort(arr,pi+1,high,steps)}else if(low===high){steps.push({type:'sorted',index:low,description:`Element ${arr[low]} at index ${low} is sorted.`,arrayState:[...arr]})}}
function partition(arr,low,high,steps){const pivot=arr[high];steps.push({type:'select_pivot',pivotIndex:high,pivotValue:pivot,description:`Choosing pivot ${pivot} at index ${high}.`,arrayState:[...arr]});let i=low-1;for(let j=low;j<high;j++){steps.push({type:'compare',i:i+1,j,pivotIndex:high,description:`Comparing ${arr[j]} (index ${j}) with pivot ${pivot}.`,arrayState:[...arr]});if(arr[j]<=pivot){i++;if(i!==j){steps.push({type:'swap',i,j,values:[arr[j],arr[i]],description:`Swapping ${arr[j]} (index ${j}) with ${arr[i]} (index ${i}).`,arrayState:[...arr]});[arr[i],arr[j]]=[arr[j],arr[i]]}}}
if(i+1!==high){steps.push({type:'swap',i:i+1,j:high,values:[arr[high],arr[i+1]],description:`Placing pivot ${pivot} at index ${i + 1}.`,arrayState:[...arr]});[arr[i+1],arr[high]]=[arr[high],arr[i+1]]}
return i+1}
function initializeSorting(){animationSteps=[];score=0;const tempArray=[...array];quickSort(tempArray,0,tempArray.length-1,animationSteps);animationSteps.push({type:'complete',description:'Victory! Array is fully sorted!',arrayState:[...tempArray]});currentStep=0;document.getElementById('prev').disabled=!0;document.getElementById('next').disabled=animationSteps.length===0;updateUI();updateHistoryLog();renderStep()}
function updateUI(){document.getElementById('array-state').textContent=`Current Array: [${array.join(', ')}]`;document.getElementById('score').textContent=`Score: ${score}`;document.getElementById('step-counter').textContent=`Step: ${currentStep}/${animationSteps.length}`;const progress=animationSteps.length?(currentStep/animationSteps.length*100).toFixed(0):0;document.getElementById('progress').textContent=`Progress: ${progress}%`;document.getElementById('progress-fill').style.width=`${progress}%`}
function updateHistoryLog(){const log=document.getElementById('history-log');log.innerHTML='';const start=Math.max(0,currentStep-4);const end=Math.min(animationSteps.length,currentStep+1);for(let i=start;i<end;i++){const p=document.createElement('p');p.textContent=`Step ${i}: ${animationSteps[i].description}`;if(i===currentStep)p.style.fontWeight='bold';log.appendChild(p)}
log.scrollTop=log.scrollHeight}
function renderStep(){if(currentStep>=animationSteps.length)return;const step=animationSteps[currentStep];document.getElementById('info').textContent=step.description;cubes.forEach(cube=>{cube.material.forEach(mat=>mat.color.set(colors.normal));cube.position.y=0;cube.scale.set(1,1,1)});array=[...step.arrayState];cubes.forEach((cube,index)=>{cube.position.x=(index-array.length/2)*spacing;cube.material[0].map=createTextTexture(array[index]);cube.material[4].map=createTextTexture(array[index]);cube.material[1].map=createTextTexture(index);cube.material[5].map=createTextTexture(index)});if(step.type==='partition_start'){for(let i=step.low;i<=step.high;i++){cubes[i].material.forEach(mat=>mat.color.set(colors.comparing));cubes[i].position.y=1}}else if(step.type==='select_pivot'){cubes[step.pivotIndex].material.forEach(mat=>mat.color.set(colors.pivot));cubes[step.pivotIndex].position.y=2;cubes[step.pivotIndex].scale.set(1.2,1.2,1.2);createPivotLine(step.pivotIndex)}else if(step.type==='compare'){if(step.i>=0){cubes[step.i].material.forEach(mat=>mat.color.set(colors.comparing));cubes[step.i].position.y=1}
cubes[step.j].material.forEach(mat=>mat.color.set(colors.comparing));cubes[step.j].position.y=1;cubes[step.pivotIndex].material.forEach(mat=>mat.color.set(colors.pivot));cubes[step.pivotIndex].position.y=2;cubes[step.pivotIndex].scale.set(1.2,1.2,1.2);createPivotLine(step.pivotIndex)}else if(step.type==='swap'){cubes[step.i].material[0].map=createTextTexture(step.values[0]);cubes[step.i].material[4].map=createTextTexture(step.values[0]);cubes[step.j].material[0].map=createTextTexture(step.values[1]);cubes[step.j].material[4].map=createTextTexture(step.values[1]);cubes[step.i].material.forEach(mat=>mat.color.set(colors.swapping));cubes[step.j].material.forEach(mat=>mat.color.set(colors.swapping));cubes[step.i].position.y=1;cubes[step.j].position.y=1;cubes[step.i].scale.set(1.1,1.1,1.1);cubes[step.j].scale.set(1.1,1.1,1.1);const tempX=cubes[step.i].position.x;cubes[step.i].position.x=cubes[step.j].position.x;cubes[step.j].position.x=tempX;playSound(440);score+=10}else if(step.type==='partition_end'){cubes[step.pivotIndex].material.forEach(mat=>mat.color.set(colors.sorted));cubes[step.pivotIndex].position.y=0;cubes[step.pivotIndex].scale.set(1,1,1);if(pivotLine)scene.remove(pivotLine);pivotLine=null}else if(step.type==='recurse'){for(let i=step.low;i<=step.high;i++){cubes[i].material.forEach(mat=>mat.color.set(colors.comparing));cubes[i].position.y=1}}else if(step.type==='sorted'){cubes[step.index].material.forEach(mat=>mat.color.set(colors.sorted));cubes[step.index].position.y=0}else if(step.type==='complete'){cubes.forEach(cube=>{cube.material.forEach(mat=>mat.color.set(colors.sorted));cube.scale.set(1,1,1)});playSound(880,'sine',0.3);const jsConfetti=new JSConfetti();jsConfetti.addConfetti({emojis:['🎉']});if(pivotLine)scene.remove(pivotLine);pivotLine=null}
updateUI();updateHistoryLog()}
let lastTime=null;function animate(time){requestAnimationFrame(animate);const positions=particles.geometry.attributes.position.array;for(let i=0;i<particleCount*3;i+=3){positions[3*i]+=velocities[3*i];positions[3*i+1]+=velocities[3*i+1];positions[3*i+2]+=velocities[3*i+2];if(Math.abs(positions[3*i])>50)velocities[3*i]*=-1;if(Math.abs(positions[3*i+1])>50)velocities[3*i+1]*=-1;if(Math.abs(positions[3*i+2])>50)velocities[3*i+2]*=-1}
particles.geometry.attributes.position.needsUpdate=!0;if(isPlaying&&currentStep<animationSteps.length){stepTimer+=time-(lastTime||time);if(stepTimer>=stepDuration/speed){renderStep();currentStep++;document.getElementById('prev').disabled=currentStep===0;document.getElementById('next').disabled=currentStep>=animationSteps.length;stepTimer=0}}
renderer.render(scene,camera);lastTime=time}
document.getElementById('start').addEventListener('click',()=>{const input=document.getElementById('numbers').value.trim();const numbers=input.split(',').map(n=>parseInt(n.trim())).filter(n=>!isNaN(n));if(numbers.length===0){alert('Please enter at least one valid integer.');return}
if(numbers.length>20){alert('Maximum 20 numbers for best experience.');return}
array=numbers;isPlaying=!1;document.getElementById('play').textContent='Play';createCubes();initializeSorting();document.getElementById('info').textContent='Sorting initialized! Navigate with buttons or play.'});document.getElementById('random').addEventListener('click',()=>{const length=Math.floor(Math.random()*8)+3;array=Array.from({length},()=>Math.floor(Math.random()*20)-10);document.getElementById('numbers').value=array.join(', ');isPlaying=!1;document.getElementById('play').textContent='Play';createCubes();initializeSorting();document.getElementById('info').textContent='Random array generated! Start sorting.'});document.getElementById('next').addEventListener('click',()=>{if(currentStep<animationSteps.length){renderStep();currentStep++;document.getElementById('prev').disabled=currentStep===0;document.getElementById('next').disabled=currentStep>=animationSteps.length}});document.getElementById('prev').addEventListener('click',()=>{if(currentStep>0){currentStep--;array=[...animationSteps[currentStep].arrayState];createCubes();renderStep();document.getElementById('prev').disabled=currentStep===0;document.getElementById('next').disabled=!1}});document.getElementById('play').addEventListener('click',()=>{isPlaying=!isPlaying;document.getElementById('play').textContent=isPlaying?'Pause':'Play';stepTimer=0});document.getElementById('speed').addEventListener('input',(e)=>{speed=parseFloat(e.target.value);document.getElementById('speed-value').textContent=`${speed.toFixed(1)}x`});document.getElementById('sound-toggle').addEventListener('click',()=>{soundEnabled=!soundEnabled;document.getElementById('sound-toggle').textContent=`Sound: ${soundEnabled ? 'On' : 'Off'}`});window.addEventListener('resize',()=>{camera.aspect=window.innerWidth/window.innerHeight;camera.updateProjectionMatrix();renderer.setSize(window.innerWidth,window.innerHeight)});animate(0);</script></body></html>